import{O as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.DGewWfie.js";import{t as r}from"./chunks/plugin-vue_export-helper.BDNMzG2s.js";var i=JSON.parse(`{"title":"關於我","description":"吳彥東（東東 / wuc656）的個人背景、教育經歷、兵役、個人特質與 GitHub 資訊。","frontmatter":{"title":"關於我","description":"吳彥東（東東 / wuc656）的個人背景、教育經歷、兵役、個人特質與 GitHub 資訊。","outline":[2,3]},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1781683122000}`),a={name:`about.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="關於我" tabindex="-1">關於我 <a class="header-anchor" href="#關於我" aria-label="Permalink to “關於我”">​</a></h1><div style="text-align:center;margin-bottom:2rem;"><h2 id="吳彥東-yen-tung-wu" tabindex="-1">吳彥東 (Yen-Tung Wu) <a class="header-anchor" href="#吳彥東-yen-tung-wu" aria-label="Permalink to “吳彥東 (Yen-Tung Wu)”">​</a></h2><p><strong>暱稱</strong>：東東 ｜ <strong>GitHub</strong>：<a href="https://github.com/wuc656" target="_blank" rel="noreferrer">wuc656</a> ｜ <strong>Email</strong>：wuc656@gmail.com</p><blockquote><p><em>「自幼因遊戲踏入電腦領域，將興趣轉化為專業職能。」</em></p></blockquote></div><hr><h2 id="基本資料" tabindex="-1">基本資料 <a class="header-anchor" href="#基本資料" aria-label="Permalink to “基本資料”">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>內容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>吳彥東 (Yen-Tung Wu)</td></tr><tr><td><strong>暱稱 / 網路 ID</strong></td><td>東東、wuc656</td></tr><tr><td><strong>出生日期</strong></td><td>2000 年 12 月 22 日</td></tr><tr><td><strong>出生地</strong></td><td>台灣苗栗市</td></tr><tr><td><strong>居住地</strong></td><td>台中市（高中時期）/ 高雄市（大學時期）</td></tr><tr><td><strong>語言</strong></td><td>繁體中文、English</td></tr><tr><td><strong>現職</strong></td><td>軟體工程師 @ <a href="https://cmis.tw/" target="_blank" rel="noreferrer">中程資訊顧問有限公司 (CMIS)</a></td></tr><tr><td><strong>Email</strong></td><td><a href="mailto:wuc656@gmail.com" target="_blank" rel="noreferrer">wuc656@gmail.com</a></td></tr></tbody></table><hr><h2 id="教育經歷" tabindex="-1">教育經歷 <a class="header-anchor" href="#教育經歷" aria-label="Permalink to “教育經歷”">​</a></h2><h3 id="🎓-國立高雄科技大學-nkust-—-資訊工程系" tabindex="-1">🎓 國立高雄科技大學 (NKUST) — 資訊工程系 <a class="header-anchor" href="#🎓-國立高雄科技大學-nkust-—-資訊工程系" aria-label="Permalink to “🎓 國立高雄科技大學 (NKUST) — 資訊工程系”">​</a></h3><p><strong>2019 – 2023</strong> ｜ 建工校區</p><p>就讀於國立高雄科技大學資訊工程系，接受了扎實的電腦科學與軟體工程訓練。在校期間學習了資料結構、演算法、資料庫、電腦網路等核心課程，為日後的全端開發工作奠定了堅實的基礎。</p><hr><h3 id="🏫-臺中市私立僑泰高級中學-—-資訊科" tabindex="-1">🏫 臺中市私立僑泰高級中學 — 資訊科 <a class="header-anchor" href="#🏫-臺中市私立僑泰高級中學-—-資訊科" aria-label="Permalink to “🏫 臺中市私立僑泰高級中學 — 資訊科”">​</a></h3><p><strong>2016 – 2019</strong> ｜ 資訊科三年甲班</p><p>就讀於臺中市私立僑泰高級中學資訊科，在此期間深入學習了程式設計、網頁設計、資料庫管理等資訊相關課程。僑泰高中資訊科以培養實務技能著稱，提供了良好的技術基礎訓練。</p><hr><h3 id="🏫-大道國民中學" tabindex="-1">🏫 大道國民中學 <a class="header-anchor" href="#🏫-大道國民中學" aria-label="Permalink to “🏫 大道國民中學”">​</a></h3><p><strong>2013 – 2016</strong></p><ul><li>2016 年國中教育會考取得 <strong>3A2B</strong> 的優異成績（A++, A+, A, B++, B+）</li><li>2015 年與 2016 年，與學校國文老師 <a href="https://www.facebook.com/dadulucy" target="_blank" rel="noreferrer">鄭麗美</a> 合作，為大道國中當屆畢業生製作畢業微電影 <ul><li><a href="https://www.youtube.com/watch?v=df7rQDfLSqU" target="_blank" rel="noreferrer">2015 畢業微電影</a></li><li><a href="https://www.youtube.com/watch?v=cpNNkTnlw68" target="_blank" rel="noreferrer">2016 畢業微電影</a></li></ul></li></ul><hr><h3 id="🏫-山陽國民小學" tabindex="-1">🏫 山陽國民小學 <a class="header-anchor" href="#🏫-山陽國民小學" aria-label="Permalink to “🏫 山陽國民小學”">​</a></h3><p><strong>~ – 2013</strong></p><p>2013 年畢業於山陽國小。</p><hr><h2 id="兵役經歷" tabindex="-1">兵役經歷 <a class="header-anchor" href="#兵役經歷" aria-label="Permalink to “兵役經歷”">​</a></h2><h3 id="🪖-陸軍志願役" tabindex="-1">🪖 陸軍志願役 <a class="header-anchor" href="#🪖-陸軍志願役" aria-label="Permalink to “🪖 陸軍志願役”">​</a></h3><p><strong>2023/09/19 – 2023/12/31</strong> ｜ 4 個月軍事訓練役</p><p>2023 年 9 月 19 日入伍，於同年 12 月 31 日結訓。在服役期間體驗了嚴格的軍事訓練，培養了紀律性與團隊合作精神。</p><hr><h2 id="個人特質" tabindex="-1">個人特質 <a class="header-anchor" href="#個人特質" aria-label="Permalink to “個人特質”">​</a></h2><h3 id="🔧-技術狂熱者" tabindex="-1">🔧 技術狂熱者 <a class="header-anchor" href="#🔧-技術狂熱者" aria-label="Permalink to “🔧 技術狂熱者”">​</a></h3><p>從小因為遊戲的關係開始研究電腦知識，雖然有時候會做一些很邪惡的事情.....但他的電腦知識比同齡的人高了許多。電腦優化、系統重灌、電腦組裝，對他來說都是輕鬆寫意的事情。</p><h3 id="📚-自學能力強" tabindex="-1">📚 自學能力強 <a class="header-anchor" href="#📚-自學能力強" aria-label="Permalink to “📚 自學能力強”">​</a></h3><p>從 Minecraft 伺服器的架設開始，自學了網路設定、Linux 系統管理、插件開發等技能。在工作中也不斷學習新技術，從 Delphi 開發者成功轉型為 Golang + Vue.js 的全端工程師。</p><h3 id="🎮-遊戲愛好者" tabindex="-1">🎮 遊戲愛好者 <a class="header-anchor" href="#🎮-遊戲愛好者" aria-label="Permalink to “🎮 遊戲愛好者”">​</a></h3><p>熱愛各類型遊戲，從 Minecraft 到英雄聯盟，再到現在的：</p><ul><li><a href="https://www.2112earthrevival.com/" target="_blank" rel="noreferrer">星球：重啟</a></li><li><a href="https://www.wherewindsmeetgame.com/hmt/index.html" target="_blank" rel="noreferrer">燕雲十六聲</a></li><li><a href="https://hsr.hoyoverse.com/zh-tw/home" target="_blank" rel="noreferrer">崩壞：星穹鐵道</a></li></ul><h3 id="🤝-社群經營者" tabindex="-1">🤝 社群經營者 <a class="header-anchor" href="#🤝-社群經營者" aria-label="Permalink to “🤝 社群經營者”">​</a></h3><p>自 2013 年起創立 Minecraft 伺服器，累積了豐富的社群經營經驗。從玩家管理、規則制定到社群推廣，展現了出色的領導與溝通能力。</p><hr><h2 id="github-成績" tabindex="-1">GitHub 成績 <a class="header-anchor" href="#github-成績" aria-label="Permalink to “GitHub 成績”">​</a></h2><p><img src="https://github-readme-stats-dong.vercel.app/api/top-langs/?username=wuc656&amp;langs_count=10&amp;layout=compact&amp;size_weight=0.5&amp;count_weight=0.5&amp;locale=zh-tw" alt="Top Langs" loading="lazy"></p><img src="https://github-readme-stats-dong.vercel.app/api?username=wuc656&amp;show_icons=true&amp;locale=zh-tw">`,42)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};